import { useState, useEffect, useRef } from 'react'
import { useNavigate, useParams, Link } from 'react-router-dom'
import { ArrowLeft, Save, UploadCloud, X, Film, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import useProductStore from '@/stores/useProductStore'
import useCategoryStore from '@/stores/useCategoryStore'
import { useToast } from '@/hooks/use-toast'
import { cn } from '@/lib/utils'
import { uploadMedia } from '@/lib/api'

export default function ProductForm() {
  const { id } = useParams()
  const nav = useNavigate()
  const { products, addProduct, updateProduct } = useProductStore()
  const { categories } = useCategoryStore()
  const { toast } = useToast()
  const fileRef = useRef<HTMLInputElement>(null)
  const [drag, setDrag] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isUploading, setIsUploading] = useState(false)

  const [form, setForm] = useState({
    title: '',
    price: '',
    categoryId: '',
    difficulty: '1',
    description: '',
    images: [] as string[],
    video: '',
    w: '',
    h: '',
    d: '',
    sheets: '',
    time: '2-3 horas',
    tags: [] as string[],
    tagInput: '',
  })

  useEffect(() => {
    if (id && products.length > 0) {
      const p = products.find((x) => x.id === id)
      if (p) {
        const [w, h, d] = p.specs.dimensions.match(/[\d.]+/g) || ['', '', '']
        setForm({
          title: p.title,
          price: String(p.price),
          categoryId: p.categoryId,
          difficulty: String(p.difficulty),
          description: p.description,
          images: p.images || [],
          video: p.video || '',
          w,
          h,
          d,
          sheets: String(p.specs.sheets),
          time: p.specs.time,
          tags: p.tags || [],
          tagInput: '',
        })
      }
    }
  }, [id, products])

  const handleChange = (e: any) => setForm((p) => ({ ...p, [e.target.id]: e.target.value }))

  const handleFiles = async (files: FileList | null) => {
    if (!files) return
    setIsUploading(true)
    try {
      const fileArray = Array.from(files)
      for (const file of fileArray) {
        const url = await uploadMedia(file)
        setForm((prev) => {
          if (file.type.startsWith('video/') && !prev.video) return { ...prev, video: url }
          if (file.type.startsWith('image/')) {
            const newImages = Array.from(new Set([...prev.images, url]))
            if (newImages.length <= 5) return { ...prev, images: newImages }
          }
          return prev
        })
      }
    } catch (err) {
      toast({ title: 'Erro no upload de mídia', variant: 'destructive' })
    } finally {
      setIsUploading(false)
    }
  }

  const handleTagKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault()
      const t = form.tagInput.replace(',', '').trim()
      if (t && !form.tags.includes(t))
        setForm((p) => ({ ...p, tags: [...p.tags, t], tagInput: '' }))
    }
  }

  const submit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!form.images.length)
      return toast({ title: 'Adicione pelo menos 1 imagem!', variant: 'destructive' })
    if (!form.categoryId)
      return toast({ title: 'Selecione uma categoria!', variant: 'destructive' })

    setIsSubmitting(true)
    const catName = categories.find((c) => c.id === form.categoryId)?.name || ''

    const p = {
      title: form.title,
      price: Number(form.price),
      categoryId: form.categoryId,
      category: catName,
      difficulty: Number(form.difficulty),
      images: form.images,
      video: form.video || undefined,
      description: form.description,
      specs: {
        sheets: form.sheets,
        time: form.time,
        dimensions: `${form.w} x ${form.h} x ${form.d} cm`,
      },
      rating: id ? products.find((x) => x.id === id)?.rating || 5 : 5,
      tags: form.tags.length ? form.tags : ['Novo'],
    }

    try {
      if (id) {
        await updateProduct(id, p)
      } else {
        await addProduct(p)
      }
      toast({ title: `Produto ${id ? 'atualizado' : 'criado'} com sucesso!` })
      nav('/admin/products')
    } catch (err) {
      toast({ title: 'Erro ao salvar produto', variant: 'destructive' })
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <div className="max-w-3xl animate-fade-in">
      <div className="flex items-center gap-4 mb-6">
        <Button variant="ghost" size="icon" asChild>
          <Link to="/admin/products">
            <ArrowLeft className="w-5 h-5" />
          </Link>
        </Button>
        <div>
          <h1 className="text-3xl font-heading font-bold">
            {id ? 'Editar Produto' : 'Novo Produto'}
          </h1>
          <p className="text-muted-foreground">Preencha as informações do modelo 3D.</p>
        </div>
      </div>
      <Card className="border shadow-subtle">
        <CardContent className="pt-6">
          <form onSubmit={submit} className="space-y-6">
            <div className="space-y-2">
              <Label>Mídia (Máx: 5 Imagens, 1 Vídeo) *</Label>
              <div
                onDragOver={(e) => {
                  e.preventDefault()
                  if (!isUploading) setDrag(true)
                }}
                onDragLeave={() => setDrag(false)}
                onDrop={(e) => {
                  e.preventDefault()
                  setDrag(false)
                  if (!isUploading) handleFiles(e.dataTransfer.files)
                }}
                onClick={() => !isUploading && fileRef.current?.click()}
                className={cn(
                  'border-2 border-dashed rounded-lg p-6 text-center transition-colors',
                  !isUploading && 'cursor-pointer',
                  drag ? 'border-primary bg-primary/10' : 'bg-muted/30',
                  isUploading && 'opacity-60 pointer-events-none',
                )}
              >
                {isUploading ? (
                  <Loader2 className="mx-auto h-8 w-8 mb-2 animate-spin text-muted-foreground" />
                ) : (
                  <UploadCloud className="mx-auto h-8 w-8 mb-2 text-muted-foreground" />
                )}
                <p className="text-sm font-medium">
                  {isUploading
                    ? 'Enviando arquivos...'
                    : 'Arraste arquivos ou clique para selecionar'}
                </p>
                <input
                  type="file"
                  ref={fileRef}
                  className="hidden"
                  multiple
                  accept="image/*,video/*"
                  onChange={(e) => handleFiles(e.target.files)}
                />
              </div>
              {(form.images.length > 0 || form.video) && (
                <div className="flex gap-4 mt-4 overflow-auto pb-2">
                  {form.images.map((img, i) => (
                    <div
                      key={i}
                      className="relative w-20 h-20 shrink-0 border rounded-md group bg-muted"
                    >
                      <img src={img} className="w-full h-full object-cover rounded-md" />
                      <button
                        type="button"
                        onClick={(e) => {
                          e.stopPropagation()
                          setForm((p) => ({ ...p, images: p.images.filter((_, idx) => idx !== i) }))
                        }}
                        className="absolute top-1 right-1 bg-background/80 rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <X className="w-3 h-3" />
                      </button>
                    </div>
                  ))}
                  {form.video && (
                    <div className="relative w-20 h-20 shrink-0 border rounded-md group bg-muted">
                      <video src={form.video} className="w-full h-full object-cover rounded-md" />
                      <Film className="absolute inset-0 m-auto w-6 h-6 text-white drop-shadow pointer-events-none" />
                      <button
                        type="button"
                        onClick={(e) => {
                          e.stopPropagation()
                          setForm((p) => ({ ...p, video: '' }))
                        }}
                        className="absolute top-1 right-1 bg-background/80 rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <X className="w-3 h-3" />
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="title">Nome *</Label>
                <Input
                  id="title"
                  required
                  value={form.title}
                  onChange={handleChange}
                  className="bg-muted/30"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price">Preço (R$) *</Label>
                <Input
                  id="price"
                  type="number"
                  step="0.01"
                  required
                  value={form.price}
                  onChange={handleChange}
                  className="bg-muted/30"
                />
              </div>
              <div className="space-y-2">
                <Label>Categoria *</Label>
                <Select
                  value={form.categoryId}
                  onValueChange={(v) => setForm((p) => ({ ...p, categoryId: v }))}
                >
                  <SelectTrigger className="bg-muted/30">
                    <SelectValue placeholder="Selecione" />
                  </SelectTrigger>
                  <SelectContent>
                    {categories.map((c) => (
                      <SelectItem key={c.id} value={c.id}>
                        {c.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Dificuldade *</Label>
                <Select
                  value={form.difficulty}
                  onValueChange={(v) => setForm((p) => ({ ...p, difficulty: v }))}
                >
                  <SelectTrigger className="bg-muted/30">
                    <SelectValue placeholder="Selecione" />
                  </SelectTrigger>
                  <SelectContent>
                    {[1, 2, 3, 4, 5].map((n) => (
                      <SelectItem key={n} value={String(n)}>
                        Nível {n}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-4 pt-4 border-t">
              <div>
                <h3 className="font-medium text-lg">Especificações Técnicas</h3>
                <p className="text-sm text-muted-foreground">
                  Dimensões: L x A x P/C (Largura, Altura, Profundidade/Comprimento).
                </p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="w">Largura (L) em cm *</Label>
                  <Input
                    id="w"
                    required
                    value={form.w}
                    onChange={handleChange}
                    className="bg-muted/30"
                    placeholder="Ex: 20"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="h">Altura (A) em cm *</Label>
                  <Input
                    id="h"
                    required
                    value={form.h}
                    onChange={handleChange}
                    className="bg-muted/30"
                    placeholder="Ex: 25"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="d">Profund. (P/C) em cm *</Label>
                  <Input
                    id="d"
                    required
                    value={form.d}
                    onChange={handleChange}
                    className="bg-muted/30"
                    placeholder="Ex: 15"
                  />
                </div>
              </div>
              <div className="grid sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="sheets">Quantidade de Folhas *</Label>
                  <Input
                    id="sheets"
                    required
                    placeholder="Ex: 5 folhas A4"
                    value={form.sheets}
                    onChange={handleChange}
                    className="bg-muted/30"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="time">Tempo de Montagem *</Label>
                  <Input
                    id="time"
                    required
                    value={form.time}
                    onChange={handleChange}
                    className="bg-muted/30"
                    placeholder="Ex: 2-3 horas"
                  />
                </div>
              </div>
            </div>

            <div className="space-y-2 pt-4 border-t">
              <Label htmlFor="tagInput">TAGs</Label>
              <Input
                id="tagInput"
                placeholder="Digite a tag e aperte Enter ou vírgula"
                value={form.tagInput}
                onChange={handleChange}
                onKeyDown={handleTagKey}
                className="bg-muted/30"
              />
              {form.tags.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-2">
                  {form.tags.map((t) => (
                    <Badge
                      key={t}
                      variant="secondary"
                      className="flex items-center gap-1 px-3 py-1"
                    >
                      {t}{' '}
                      <button
                        type="button"
                        onClick={() =>
                          setForm((p) => ({ ...p, tags: p.tags.filter((x) => x !== t) }))
                        }
                        className="hover:text-destructive"
                      >
                        <X className="w-3 h-3" />
                      </button>
                    </Badge>
                  ))}
                </div>
              )}
            </div>

            <div className="space-y-2 pt-4 border-t">
              <Label htmlFor="description">Descrição *</Label>
              <Textarea
                id="description"
                required
                rows={4}
                value={form.description}
                onChange={handleChange}
                className="bg-muted/30 resize-none"
              />
            </div>

            <div className="flex gap-4 pt-4 border-t">
              <Button
                type="button"
                variant="outline"
                className="flex-1"
                onClick={() => nav('/admin/products')}
              >
                Cancelar
              </Button>
              <Button type="submit" disabled={isSubmitting || isUploading} className="flex-1">
                {isSubmitting ? (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                ) : (
                  <Save className="w-4 h-4 mr-2" />
                )}
                {id ? 'Salvar Alterações' : 'Criar Produto'}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}
